    SELECT ?state (COUNT(?event2) AS ?count2010)
    WHERE {
      ?event2 a goo:StormEventRecord ;
              goo:occurredInState ?state ;
              goo:eventStartTime ?time2 .
      FILTER(?time2 >= "2010-01-01T00:00:00Z"^^xsd:dateTime && ?time2 < "2011-01-01T00:00:00Z"^^xsd:dateTime)
