  ?county rdfs:label ?countyLabel ;
          goo:neighboringCounties ?neighbor .
  FILTER(CONTAINS(LCASE(?countyLabel), "lee") || CONTAINS(LCASE(?countyLabel), "fort myers"))

  ?rec a goo:CustomerOutageRecord ;
       goo:representsCounty ?neighbor ;
       goo:numberOfOutages ?outages ;
       goo:recordDateTime ?recTime .
  FILTER(?recTime >= "2022-09-25T00:00:00Z"^^xsd:dateTime && ?recTime <= "2022-10-05T00:00:00Z"^^xsd:dateTime)

  ?svi a goo:SVIRecord ;
       goo:representsCounty ?neighbor ;
       goo:sviOverallScore ?sviScore .
  FILTER(?sviScore > 0.5)
}
ORDER BY DESC(?outages) DESC(?sviScore)
