       goo:representsCounty ?county ;
       goo:sviYear 2022 ;
       goo:sviOverallScore ?sviScore .
  FILTER(?sviScore >= 0.8)

  ?event a goo:StormEventRecord ; 
         goo:occurredInCounty ?county ;
         goo:eventStartTime ?startTime .
  FILTER(?startTime >= "2022-01-01T00:00:00Z"^^xsd:dateTime && ?startTime < "2023-01-01T00:00:00Z"^^xsd:dateTime)
}
GROUP BY ?county
LIMIT 10

PREFIX goo: <https://ucf-henat.github.io/GeoOutageOnto/#>
