SELECT ?state ?stateLabel ?hurricaneCount ?avgSvi
WHERE {
  {
    SELECT ?state (COUNT(?event) AS ?hurricaneCount)
    WHERE {
      ?event a goo:StormEventRecord ;
             goo:stormEventType ?type ;
             goo:occurredInState ?state .
      FILTER(CONTAINS(LCASE(?type), "hurricane"))
    }
    GROUP BY ?state
  }
  {
    SELECT ?state (AVG(?sviScore) AS ?avgSvi)
    WHERE {
      ?county goo:locatedInState ?state .
      ?svi a goo:SVIRecord ;
           goo:representsCounty ?county ;
           goo:sviOverallScore ?sviScore .
    }
    GROUP BY ?state
  }
  ?state rdfs:label ?stateLabel .
}
ORDER BY DESC(?hurricaneCount)
LIMIT 10

